import 'package:flutter/services.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  final FlutterSecureStorage _secureStorage;
  final SharedPreferences _prefs;

  AuthenticationManager() : _secureStorage = FlutterSecureStorage(), _prefs = await SharedPreferences.getInstance();

  Future<void> saveAuthTokensAndUserData(String accessToken, String refreshToken, dynamic userData) async {
    await _secureStorage.write(key: 'access_token', value: accessToken);
    await _secureStorage.write(key: 'refresh_token', value: refreshToken);
    await _prefs.setString('user_data', jsonEncode(userData));
  }

  Future<Map<String, dynamic>> loadAuthTokensAndUserData() async {
    String accessToken = await _secureStorage.read(key: 'access_token');
    String refreshToken = await _secureStorage.read(key: 'refresh_token');
    String userDataStr = _prefs.getString('user_data');
    Map<String, dynamic> userData;
    if (userDataStr != null) {
      userData = jsonDecode(userDataStr);
    }
    return {'access_token': accessToken, 'refresh_token': refreshToken, 'user_data': userData};
  }

  Future<void> clearAuthData() async {
    await _secureStorage.deleteAll();
    await _prefs.clear();
  }
}